import { useFocusEffect, useNavigation } from '@react-navigation/native';
import { NativeStackNavigationProp } from '@react-navigation/native-stack';
import React, { useCallback, useContext, useMemo, useState } from 'react';
import { Pressable, SafeAreaView, ScrollView, StyleSheet, Text, View } from 'react-native';
import { AuthContext } from '../../App';
import CustomerBottomNav from '../components/CustomerBottomNav';
import OrderStatusTracker from '../components/OrderStatusTracker';
import {
  formatCurrency,
  formatOrderDate,
  formatOrderNumber,
  getReminderText,
  getSuggestedQuantity,
  ORDER_STATUS_META,
  WATER_PRODUCT
} from '../data/orderModule';
import { RootStackParamList } from '../navigation/AppNavigator';
import { fetchCustomerOrders, OrderRecord } from '../services/firebaseService';

type NavigationProp = NativeStackNavigationProp<RootStackParamList, 'CustomerHome'>;

const CustomerHomeScreen = () => {
  const { profile } = useContext(AuthContext);
  const navigation = useNavigation<NavigationProp>();
  const [orders, setOrders] = useState<OrderRecord[]>([]);

  useFocusEffect(
    useCallback(() => {
      let active = true;
      const loadOrders = async () => {
        if (!profile?.uid) {
          setOrders([]);
          return;
        }
        const data = await fetchCustomerOrders(profile.uid).catch(() => []);
        if (active) {
          setOrders(data);
        }
      };

      loadOrders();
      return () => {
        active = false;
      };
    }, [profile?.uid])
  );

  const activeOrder =
    orders.find((order) => ['pending', 'confirmed', 'preparing', 'out_for_delivery'].includes(order.status)) ?? null;
  const reminderText = useMemo(() => getReminderText(orders), [orders]);
  const suggestedQuantity = getSuggestedQuantity(orders);
  const lastOrder = orders[0] ?? null;

  return (
    <SafeAreaView style={styles.container}>
      <ScrollView contentContainerStyle={styles.content} showsVerticalScrollIndicator={false}>
        <View style={styles.headerRow}>
          <View>
            <Text style={styles.welcomeText}>Thannican</Text>
            <Text style={styles.headerTitle}>Fresh water at your doorstep</Text>
            <Text style={styles.headerSubtitle}>Hello {profile?.name || 'Customer'}, ordering is simple today.</Text>
          </View>
          <Pressable style={styles.profileButton} onPress={() => navigation.navigate('Profile')}>
            <Text style={styles.profileButtonText}>Profile</Text>
          </Pressable>
        </View>

        <View style={styles.heroCard}>
          <Text style={styles.heroPill}>Family friendly water delivery</Text>
          <Text style={styles.heroTitle}>Book 20L cans with large clear steps</Text>
          <Text style={styles.heroSubtitle}>
            Blue and white design, simple English, quick order flow, and live order updates for every delivery.
          </Text>
          <View style={styles.heroActionRow}>
            <Pressable style={styles.primaryButton} onPress={() => navigation.navigate('NewOrder')}>
              <Text style={styles.primaryButtonText}>Order Water Now</Text>
            </Pressable>
            <Pressable style={styles.secondaryButton} onPress={() => navigation.navigate('CustomerOrders')}>
              <Text style={styles.secondaryButtonText}>My Orders</Text>
            </Pressable>
          </View>
        </View>

        <View style={styles.reminderCard}>
          <Text style={styles.reminderLabel}>Smart reminder</Text>
          <Text style={styles.reminderText}>{reminderText}</Text>
          <Pressable
            style={styles.reminderButton}
            onPress={() => navigation.navigate('NewOrder', { reorder: true })}
          >
            <Text style={styles.reminderButtonText}>Reorder {suggestedQuantity} cans</Text>
          </Pressable>
        </View>

        <View style={styles.infoRow}>
          <View style={styles.infoCard}>
            <Text style={styles.infoLabel}>Price</Text>
            <Text style={styles.infoValue}>{formatCurrency(WATER_PRODUCT.pricePerCan)}</Text>
            <Text style={styles.infoHint}>Per 20L can</Text>
          </View>
          <View style={styles.infoCard}>
            <Text style={styles.infoLabel}>Available now</Text>
            <Text style={styles.infoValue}>{WATER_PRODUCT.availableStock}</Text>
            <Text style={styles.infoHint}>Cans in stock</Text>
          </View>
        </View>

        {activeOrder ? (
          <View style={styles.sectionCard}>
            <View style={styles.sectionHeader}>
              <View>
                <Text style={styles.sectionTitle}>Current active order</Text>
                <Text style={styles.sectionSubtitle}>
                  {formatOrderNumber(activeOrder)} | {formatCurrency(activeOrder.totalAmount)}
                </Text>
              </View>
              <Pressable onPress={() => navigation.navigate('OrderTracking', { orderId: activeOrder.id })}>
                <Text style={styles.linkText}>Track</Text>
              </Pressable>
            </View>
            <OrderStatusTracker status={activeOrder.status} compact />
            <View style={styles.activeOrderMeta}>
              <Text style={styles.activeOrderMetaText}>Quantity: {activeOrder.quantity} cans</Text>
              <Text style={styles.activeOrderMetaText}>ETA: {activeOrder.expectedDeliveryTime}</Text>
            </View>
          </View>
        ) : (
          <View style={styles.emptyCard}>
            <Text style={styles.emptyTitle}>No active order right now</Text>
            <Text style={styles.emptyText}>Tap Order Water Now to book fresh water for your home.</Text>
          </View>
        )}

        <View style={styles.sectionCard}>
          <Text style={styles.sectionTitle}>Quick reorder</Text>
          <Text style={styles.sectionSubtitle}>Based on your previous purchase history</Text>
          {lastOrder ? (
            <View style={styles.lastOrderCard}>
              <View>
                <Text style={styles.lastOrderTitle}>{formatOrderNumber(lastOrder)}</Text>
                <Text style={styles.lastOrderSubtext}>
                  {lastOrder.quantity} cans | {formatOrderDate(lastOrder.createdAt)}
                </Text>
              </View>
              <Pressable
                style={styles.smallPrimaryButton}
                onPress={() => navigation.navigate('NewOrder', { reorder: true })}
              >
                <Text style={styles.smallPrimaryButtonText}>Order Again</Text>
              </Pressable>
            </View>
          ) : (
            <Text style={styles.emptyInlineText}>Your quick reorder card will appear after your first order.</Text>
          )}
        </View>

        <View style={styles.sectionCard}>
          <Text style={styles.sectionTitle}>Weekly Water Plan</Text>
          <Text style={styles.sectionSubtitle}>Set a simple plan and avoid repeated booking every week.</Text>
          <Pressable
            style={styles.secondaryWideButton}
            onPress={() => navigation.navigate('CustomerSubscription')}
          >
            <Text style={styles.secondaryWideButtonText}>Open Subscription</Text>
          </Pressable>
        </View>

        {lastOrder ? (
          <View style={styles.sectionCard}>
            <Text style={styles.sectionTitle}>Recent order summary</Text>
            <Text style={styles.sectionSubtitle}>Last delivery details</Text>
            <View style={styles.recentSummaryCard}>
              <Text style={styles.recentSummaryTitle}>{formatOrderNumber(lastOrder)}</Text>
              <Text style={styles.recentSummaryText}>
                Delivery status: {ORDER_STATUS_META[lastOrder.status].label}
              </Text>
              <Text style={styles.recentSummaryText}>Amount: {formatCurrency(lastOrder.totalAmount)}</Text>
              <Text style={styles.recentSummaryText}>Payment: {lastOrder.paymentMethod}</Text>
            </View>
          </View>
        ) : null}
      </ScrollView>
      <CustomerBottomNav active="CustomerHome" />
    </SafeAreaView>
  );
};

const styles = StyleSheet.create({
  container: {
    flex: 1,
    backgroundColor: '#F2F9FF'
  },
  content: {
    padding: 18,
    paddingBottom: 110
  },
  headerRow: {
    flexDirection: 'row',
    justifyContent: 'space-between',
    alignItems: 'flex-start'
  },
  welcomeText: {
    color: '#0D8DD8',
    fontSize: 13,
    fontWeight: '800',
    textTransform: 'uppercase'
  },
  headerTitle: {
    marginTop: 8,
    color: '#10324A',
    fontSize: 28,
    fontWeight: '900'
  },
  headerSubtitle: {
    marginTop: 8,
    color: '#5E788C',
    fontSize: 14,
    lineHeight: 21
  },
  profileButton: {
    borderRadius: 16,
    backgroundColor: 'white',
    paddingHorizontal: 14,
    paddingVertical: 10
  },
  profileButtonText: {
    color: '#0D63A8',
    fontSize: 13,
    fontWeight: '800'
  },
  heroCard: {
    marginTop: 18,
    backgroundColor: '#DFF4FF',
    borderRadius: 30,
    padding: 20
  },
  heroPill: {
    alignSelf: 'flex-start',
    backgroundColor: 'rgba(255,255,255,0.88)',
    borderRadius: 999,
